import unittest

class TestSolution(unittest.TestCase):
    def test_basic_prefix(self):
        contacts = {"Alice": "555-1234", "Bob": "555-5678", "Alicia": "555-9012"}
        result = phone_directory(contacts, "Ali")
        self.assertEqual(result, {"Alice": "555-1234", "Alicia": "555-9012"})

    def test_no_match(self):
        contacts = {"Alice": "555-1234", "Bob": "555-5678"}
        result = phone_directory(contacts, "Ch")
        self.assertEqual(result, {})

    def test_case_insensitive(self):
        contacts = {"Alice": "555-1234", "bob": "555-5678"}
        result = phone_directory(contacts, "alice")
        self.assertEqual(result, {"Alice": "555-1234"})

    def test_hidden_empty_contacts(self):
        result = phone_directory({}, "A")
        self.assertEqual(result, {})

    def test_hidden_empty_query(self):
        contacts = {"Alice": "555-1234", "Bob": "555-5678"}
        result = phone_directory(contacts, "")
        self.assertEqual(result, {"Alice": "555-1234", "Bob": "555-5678"})

    def test_hidden_exact_match(self):
        contacts = {"Alice": "555-1234"}
        result = phone_directory(contacts, "Alice")
        self.assertEqual(result, {"Alice": "555-1234"})

    def test_hidden_query_longer_than_name(self):
        contacts = {"Al": "555-1234"}
        result = phone_directory(contacts, "Alice")
        self.assertEqual(result, {})

    def test_hidden_multiple_same_prefix(self):
        contacts = {"John": "111", "Johnny": "222", "Jonathan": "333", "Jane": "444"}
        result = phone_directory(contacts, "Jo")
        self.assertEqual(result, {"John": "111", "Johnny": "222", "Jonathan": "333"})

if __name__ == '__main__':
    unittest.main()
